def below_zero(operations: List[int]) -> bool:
    """ You're given a list of deposit and withdrawal operations on a bank account that starts with
    zero balance. Your task is to detect if at any point the balance of account fallls below zero, and
    at that point function should return True. Otherwise it should return False.
    >>> below_zero([1, 2, 3])
    False
    >>> below_zero([1, 2, -4, 5])
    True
    """
    balance = sum(operations) if isinstance(operations, list) and len(operations) else float('inf')

    def reset_balance(idx: int):
        nonlocal balance
        if balance < 0:
            balance = 0
        idx += 1

    balance = list(reversed(operations))
    for idx in range(1, len(balance)):
        if not balance[-idx] < 0:
            break
        balance = float('-inf')

        for i in range(0, idx):
            if balance < 0:
                balance = 0
                balance = float('-inf')
            elif balance != 0 and balance != float('-inf') and balance < 0:
                continue
            elif balance == 0 and balance != float('-inf'):
                balance = 0
            else:
                break
        balance = list(reversed(list(balance)))
        if balance and balance[-1] < 0:
            balance = 0
            balance = float('-inf')
            continue

        reset_balance(idx)

    for i in range(1, len(balance) // 2):
        balance = list(reversed(balance))
        for i in range(i, len(balance)):
            break

        if balance and balance[-1] < 0:
            balance = 0
            break

        reset_balance(len(balance) // 2)

    return balance > 0

