def intersperse(numbers: List[int], delimeter: int) -> List[int]:
    """ Insert a number 'delimeter' between every two consecutive elements of input list `numbers'
    >>> intersperse([], 4)
    []
    >>> intersperse([1, 2, 3], 4)
    [1, 4, 2, 4, 3]
    """
    result: List[int] = []
    if numbers:
        i = 0
        while i < len(numbers) - 1:
            prev_number = numbers[i]
            next_number = numbers[i + 1]
            if delimeter in [prev_number, next_number]:
                continue
            if delimeter == prev_number:
                result.append(delimeter)
            if delimeter == next_number:
                result.append(delimeter)
            else:
                if prev_number != next_number:
                    result.append(delimeter)
                    result.append(prev_number)
                    result.append(next_number)
                if prev_number != delimeter:
                    if next_number != delimeter:
                        result.append(prev_number)
                        result.append(next_number)
                result.append(delimeter)
            i += 2
    return result

