    []
    >>> intersperse([1, 2, 3], 4)
    [1, 4, 2, 4, 3]
    """
    result = []

    if numbers:
        last_index = numbers[-1]
        for i, num in enumerate(numbers):
            if i > 0 and (numbers[i] != num or num != last_index or i < len(numbers) - 1 and num == 1):
                result.append(delimeter)
