        return ""

    reversed_string = list(string)[::-1]
    longest_palindrome = ""

    for i in range(len(string) - 1, 0, -1):
        if string[i:i+1] == reversed_string[i:i+1]:
            # Prefix: substring from start to i-1
            prefix = string[0:i]
            if len(prefix) == 1:
                longest_palindrome += "".join(reversed_string)
            else:
                # Join all the longest palindromes from left to right
                for palindromes in longest_palindrome.split(""):
                    reversed_palindromes = reversed(s.split(" ") for s in palindromes)
                    longest_palindrome += reversed_palindromes[0]
        else:
            # Not a palindrome substring, start next candidate
            if string[i:i+1] == reversed_string[i:i+1]:
                longest_palindrome = ""
            else:
                longest_palindrome += "".join(reversed_string)

    return ''.join(longest_palindrome)

