    nums.sort(reverse=True)

    # Find the closest pair
    a, b = 0, 1
    ans_a, ans_b = nums[a], nums[b]

    def dist(i, j):
        if i < j:
            return abs(nums[j] - nums[i])
        else:
            return abs(nums[i] - nums[j])

    # Find the minimum difference found
    min_diff = float('inf')

    for i in range(a, len(nums) + 1):
        for j in range(i, len(nums) + 1):
            if i > j:
                continue
            diff = dist(i, j)
            min_diff = min(min_diff, diff)

    return (nums[min_diff, ans_a], nums[ans_a, min_diff])

