def fib4(n: int):
    # Initialize variables for memoized calculation starting from n-4 down to 0
    memo = {}

    def f4(m):
        if m in memo:
            return memo[m]
        # fib4(m) = fib4(m-1) + fib4(m-2) + fib4(m-3) + fib4(m-4)
        # Initialize base cases for m < 4
        f4(0) = 0
        f4(1) = 0
        f4(2) = 2
        f4(3) = 0
        val = (f4(m - 1) + f4(m - 2) + f4(m - 3) + f4(m - 4))
        memo[m] = val
        return val

    return f4(n)

