    def is_palindrome_with_prefix_suffix(text):
        prefix = text[:len(text)//2]
        prefix2 = text[len(prefix):]
        left = 0
        right = len(prefix2) - 1

        while left <= right:
            if left < len(prefix2):
                if prefix2[left] != prefix2[right]:
                    return False
            else:
                left += 1

            if left < len(prefix):
                if prefix[left] != prefix2[left]:
                    return False
            right -= 1

        return True

    if not is_palindrome_with_prefix_suffix(text):
        return False

    return True

def modp(n: int, p: int):
    if n < 0:
        raise ValueError("n must be non-negative")
    result = 1
    power = n
    while power > 0:
        if power % 2 == 1:
            result = (result * p) % p
        power >>= 1
        # If n is negative, the modular exponentiation should be:
        if n < 0:
            if power % 2 == 0:
                return result * p % p
            else:
                return pow(2, power // 2) % p
    return result * p % p

