    odd = 0
    for i in range(len(arr)):
        if i % 2 == 0:  # Even positions (0, 2, 4...)
            if arr[i] in range(48, 57, 1):
                even += 1
            else:
                odd += 1
        else:  # Odd positions (1, 3, 5...)
            if arr[i] in range(48, 57, 1):
                even += 1
            else:
                odd += 1

    # Add base even and odd counts if digits exist
    base_even = (len(arr) % 2 == 0)
    base_odd = (len(arr) % 2 == 1)

    smallest_even = even if even >= base_even else odd
    smallest_odd = odd if odd >= base_odd else even

    # Final result is even + (remaining odd) + smallest_odd if odd
    if smallest_odd < 0:
        smallest_odd = smallest_odd  # No additional adjustment

    return smallest_even + smallest_odd

