        if n <= 1:
            return False
        if n <= 3:
            return True
        if n % 2 == 0 or n % 3 == 0:
            return False
        i = 5
        while i * i <= n:
            if n % i == 0 or n % (i + 2) == 0:
                return False
            i += 6
        return True

    if not isinstance(length, int) or length < 2:
        return False

    return is_prime(length)

def prime_length(string):
    """Write a function that takes a string and returns True if the string
    length is a prime number or False otherwise
    Examples
    prime_length('Hello') == True
    prime_length('abcdcba') == True
    prime_length('kittens') == True
    prime_length('orange') == False
    """
    # Handle edge cases: empty string, single character (non-zero length if considering as a number), and zero
    length = len(string) if string else 0

    if length == 0 or length == 1:
        return False

    # Check if length > 1
    if length <= 1:
        return False

    # Convert to integer to check divisibility by numbers 2 to length-1
    try:
        num = int(length)
        if num < 0:
            return False
        if num < 2:
            return False
        for i in range(2, num):
            if length % i == 0:
                return False
        return True
    except ValueError:
        return False

