    if n == 1:
        return min(nums)

    min_sum = min(nums)
    max_sum = max(nums)
    min_sub_sum = max(nums)  # when n >= 2

    if min_sub_sum < 0:
        # all numbers are negative -> choose smallest single element
        return min(nums)
    elif min_sub_sum == 0:
        # all numbers are non-negative, choose 0
        return 0

    # Binary search approach for optimization
    low = 0
    high = n - 1
    idx = (low + high) // 2

    left_sub_sum = min(nums[:idx], nums[idx+1:])
    right_sub_sum = min(nums[1:idx], nums[idx:])

    if left_sub_sum < right_sub_sum:
        idx = idx - 1

    if idx + 1 < n:
        if min(nums[1:idx]) + min(nums[idx:]) < right_sub_sum:
            idx = idx + 1
        else:
            idx = idx

    sub_nums = nums[idx+1:] if idx + 1 < n else nums[:]
    return min_SubArraySum(sub_nums)

