    import math

    def find_max_row_index(row, index):
        """Returns the index of the first element equal to 1, else -1."""
        for i in range(index, len(row)):
            if row[i] == 1:
                return i
        return -1

    def get_well_volume():
        """Returns cumulative 1s from a given position onward for the current row."""
        wlen = len(grid[0])
        count = 0
        for r in range(len(grid)):
            for c in range(wlen):
                if 0 < c < wlen - 1:
                    count += grid[r][c]
        return count

    def get_remaining_volume(grid, current_wel, capacity):
        """Given the current well index and a bucket capacity, returns how many additional buckets can empty it."""
        wlen = len(grid[0])
        current_vol = get_well_volume(grid, current_wel, wlen)
        remaining = current_vol - capacity
        if remaining <= 0:
            return 0
        # We need to find smallest non-negative r such that row[r] has a 1
        for r, row in enumerate(grid):
            idx = get_well_volume(grid, r, wlen)
            if idx <= remaining:
                return r
        return -1

    max_buckets = 0
    best_bucket_index = -1
    for r, row in enumerate(grid):
        res = find_max_row_index(row, r)
        if res == -1:
            # No empty spot, max_buckets stays same
            pass
        else:
            buckets = res - 1 + max_buckets
            max_buckets = max(max_buckets, buckets)
            best_bucket_index = res

    return best_bucket_index + 1

