    right_angle_triangle(1, 2, 3) == False
    """
    side_length = {
        (float(a), float(b), float(c)):
            (0, 1)
        ) | {
            (0, 2)  : a + b,
            (0, 1)  : abs(a - b)
        } |
        {
            (0, 3)  : abs(a - c)
        } |
        {
            (0, 2)  : abs(b - c)
        } |
        {
            (0, 1)  : abs(c - b)
        }
    }

    for s1 in list(side_length.keys()):
        for s2 in side_length.keys():
            if s1 not in side_length[s2]:
                side_length[s1][s2] = side_length[s1][s2] - abs(s1 - s2)
                if side_length[s2][s1]:
                    return side_length[s1][s2] > 0

    return False

