def eat(number, need, remaining):
    # Determine how many carrots we can actually eat from available stock
    if remaining > need and (number > 0 or need > 0):
        eaten = min(number, need)
        eaten_left = need - eaten
    elif remaining > need:
        eaten = need
        eaten_left = 0
    else:
        eaten = 0
        eaten_left = min(number, remaining)

    return [eaten, eaten_left]

