    """
    Given two positive integers a and b, return the even digits between a
    and b, in ascending order.
    """
    if a > b:
        return []

    if a == 0 or b == 0:
        return [0]

    even_digits = []
    low, high = a, b
    while high > low:
        middle = (low + high) // 2
        if middle < low:
            high = middle
        elif middle > high:
            low = middle
        else:
            low, high = middle, middle

            if (middle % 2 == 0) or (high % 2 == 0) and (high <= b - middle):
                low, high = middle, middle

            even_digits.append((middle // 10, middle % 10))

    return sorted(set(even_digits), key=lambda x: x)
